import fs from 'fs';

class LRUList {
  private readonly capacity: number;
  private readonly map: Map<string, { node: LRUNode; value: number }>;

  constructor(capacity: number) {
    this.capacity = capacity;
    this.map = new Map();
    this.head = new LRUNode(); // sentinel
    this.tail = new LRUNode(); // sentinel
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private head: LRUNode;
  private tail: LRUNode;

  // Add new node at the head (most recently used)
  add(key: string, value: number): void {
    const node = new LRUNode();
    const prev = this.head;
    const next = this.head.next;

    prev.next = node;
    node.prev = prev;
    node.next = next;
    next.prev = node;

    this.map.set(key, { node, value });
  }

  // Move existing node to head (most recently used)
  moveToMRU(key: string): void {
    const { node } = this.map.get(key)!;
    this.remove(node);
    this.add(key, node.value);
  }

  // Remove node from list
  remove(node: LRUNode): void {
    const prev = node.prev;
    const next = node.next;
    prev.next = next;
    next.prev = prev;
    this.map.delete(node.key);
  }

  // Evict least recently used (at tail)
  evict(): void {
    if (this.tail === this.head) return;
    const node = this.tail.prev;
    this.remove(node);
  }

  // Check if cache is full
  isFull(): boolean {
    return this.size() >= this.capacity;
  }

  size(): number {
    return this.map.size;
  }
}

class LRUNode {
  key: string;
  value: number;
  prev: LRUNode;
  next: LRUNode;

  constructor() {
    this.key = '';
    this.value = 0;
    this.prev = null as any;
    this.next = null as any;
  }
}

class LRUCache {
  private readonly capacity: number;
  private readonly list: LRUList;
  private readonly map: Map<string, number>;

  constructor(capacity: number) {
    this.capacity = capacity;
    this.list = new LRUList(capacity);
    this.map = new Map();
  }

  get(key: string): number {
    if (!this.map.has(key)) return -1;
    this.list.moveToMRU(key);
    return this.map.get(key)!;
  }

  put(key: string, value: number): void {
    if (this.map.has(key)) {
      this.map.set(key, value);
      this.list.moveToMRU(key);
    } else {
      this.list.add(key, value);
      this.map.set(key, value);
    }
  }

  del(key: string): void {
    if (this.map.has(key)) {
      this.list.remove(this.list.map.get(key)!.node);
      this.map.delete(key);
    }
  }

  getMRUList(): string[] {
    const result: string[] = [];
    let current: LRUNode = this.list.head.next;
    while (current !== this.list.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }
}

// Main code
const data = fs.readFileSync(0, 'utf8');
const lines = data.trim().split('\n');
const [C, N] = lines[0].split(' ').map(Number);

const cache = new LRUCache(C);
const getResults: number[] = [];
let keysInCache: string[] = [];

for (let i = 1; i <= N; i++) {
  const parts = lines[i].split(' ');
  const op = parts[0];
  const key = parts[1];

  if (op === 'GET') {
    const value = cache.get(key);
    getResults.push(value);
  } else if (op === 'PUT') {
    const value = parseInt(parts[2]);
    cache.put(key, value);
  } else if (op === 'DEL') {
    cache.del(key);
  }
}

// Output results
if (getResults.length === 0) {
  console.log('EMPTY');
} else {
  console.log(getResults.join(' '));
}

// Output remaining keys
const remaining = cache.getMRUList();
if (remaining.length === 0) {
  console.log('EMPTY');
} else {
  console.log(remaining.join(' '));
}
